import React, { createContext, useState, useContext } from 'react';

const DataContext = createContext(null);

export const DataProvider = ({ children }) => {
  // 1. Danh sách nhân sự
  const [staffList, setStaffList] = useState([
    { id: 1, username: 'nv1', password: '123', name: 'Nguyễn Văn A', role: 'staff' },
    { id: 2, username: 'nv2', password: '123', name: 'Trần Thị B', role: 'staff' },
  ]);

  // 2. Danh sách công việc (Tasks)
  const [tasks, setTasks] = useState([
    { id: 1, title: 'Soạn giáo án K12', assigneeId: 1, progress: 30 },
    { id: 2, title: 'Kiểm tra thiết bị phòng Lab', assigneeId: 2, progress: 0 },
  ]);

  // 3. Log điểm danh
  const [attendanceLogs, setAttendanceLogs] = useState([]);

  // 4. Log kiểm tra CSVC
  const [facilityLogs, setFacilityLogs] = useState([]);

  // Actions
  const addStaff = (newStaff) => setStaffList([...staffList, { ...newStaff, id: Date.now() }]);
  const addTask = (newTask) => setTasks([...tasks, { ...newTask, id: Date.now(), progress: 0 }]);
  const updateTaskProgress = (taskId, progress) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, progress } : t));
  };
  const addAttendance = (log) => setAttendanceLogs([...attendanceLogs, log]);
  const addFacilityLog = (log) => setFacilityLogs([...facilityLogs, log]);

  return (
    <DataContext.Provider value={{
      staffList, addStaff,
      tasks, addTask, updateTaskProgress,
      attendanceLogs, addAttendance,
      facilityLogs, addFacilityLog
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => useContext(DataContext);
